def _load_audio_16k_mono(audio_path: Path) -> tuple[np.ndarray, int]:
  y, sr = sf.read(str(audio_path))
  if y.ndim > 1:
    y = np.mean(y, axis=1)
  if sr != 16000:
    y = librosa.resample(y.astype(np.float32), orig_sr=sr, target_sr=16000)
    sr = 16000
  if y.dtype != np.float32:
    y = y.astype(np.float32)
  return y, sr


